export interface ToolResult {
    success: boolean;
    output: string;
    error?: string;
    diff?: FileDiff;
}

export interface ToolDefinition {
    name: string;
    description: string;
    parameters: Record<string, { type: string; description: string; required?: boolean }>;
}

